	var $cursorX;
	var $cursorY;
	var $cursorP;
	
	var $color; 
	
						
	function Vpu(){
		$this->color = 6;
		$this->width = VPU_WIDTH;
		$this->height = VPU_HEIGHT;
		$this->cursorX = 0;
		$this->cursorY = 0;
		$this->cursorP = 0;
		
		$this->clear(0);
	}
	
	function setColor($color){
		$this->color = $color;
	}
	
	function locateCursor($x, $y){
		$this->cursorX = $x;
		$this->cursorY = $y;
		$this->cursorP = ($y * ( $this->width <<1 )) +$x;
		if($x >= $this->width <<1 )$x = ( $this->width <<1 ) -1;
		if($y >= $this->height ) $this->cursorY = ( $this->height ) -1;
	}
	
	function clear($bgcolor = 0x0){
		foreach($this->data0 as &$i) $i = $bgcolor;
		foreach($this->data1 as &$i) $i = 0x0;
		foreach($this->data2 as &$i) $i = 0x100;
	}
	
	function putTile(&$data, $x, $y, $tile, $color=0){
		$data[($y * ($this->width)) + $x]=($color<<12)|$tile;		
	}
	
	// Output ascii text, each char ocuppies half of the width of a screen tile.
	function putAscii($string){			
		foreach(str_split($string) as $i){
			$this->putChar_2(ord($i)+0x100);
		}
	}
	
	function putChar_2($index){
		// Quick Fucking dirty hack...
		switch($index){
			case ord("á"): $index = 256 + 160; break;
			case ord("é"): $index = 256 + 130; break;
			case ord("í"): $index = 256 + 161; break;
			case ord("ó"): $index = 256 + 162; break;
			case ord("ú"): $index = 256 + 163; break;		
			case ord("Á"): $index = 256 + 160; break;//181
			case ord("É"): $index = 256 + 144; break;//144
			case ord("Í"): $index = 256 + 161; break;//214
			case ord("Ó"): $index = 256 + 162; break;//224
			case ord("Ú"): $index = 256 + 163; break;//233
		}
	
		
		// Write value to 'screen'
		$this->cursorP = ($this->cursorY * ($this->width)) + ($this->cursorX>>1);
		if($this->cursorX & 1 ) {
			$this->data2[$this->cursorP] = ($this->color<<12)|($index&0x0FFF);
		} else {
			$this->data2[$this->cursorP] = 0x0100;
			$this->data1[$this->cursorP] = ($this->color<<12)|($index&0x0FFF);
		}

		
		// Clamp cursor to visible area
		if($this->cursorY == $this->height){ 
			//scroll a line
			$this->cursorX = 0;
		} else {
			$this->cursorY = $this->cursorX < ($this->width <<1)-1 ? $this->cursorY : $this->cursorY+1;
			$this->cursorX = $this->cursorX < ($this->width <<1)-1 ? $this->cursorX+1 : 0;
		}
	}
	
	function dump(){
		echo "{" .	'"command" : "blit", '.
			'"width" : "'.VPU_WIDTH.'", ' .
			'"height" : "'.VPU_HEIGHT.'", ' .
			'"data0" : ' . json_encode($this->data0) . ", ".
			'"data1" : ' . json_encode($this->data1) . ", ".
			'"data2" : ' . json_encode($this->data2) . "}";
	}
